SELECT COUNT(DISTINCT LPB.PK) AS TOTAL FROM LATTES_P_PRODBIB LP JOIN LATTES_PRODBIB LPB ON LPB.PK = LP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LP.FK_SIAPE WHERE LOWER(LPB.TIPO) = LOWER('capitulo de livro') AND CAST(NULLIF(LPB.ANO, '') AS INTEGER) = 2021 AND LOWER(S.SIGLA_CAMPUS) = LOWER('apa') AND (LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%educacao%' OR LOWER(COALESCE(S.AREA_INGRESSO_OG, '')) LIKE '%educacao%')